VALUES
  ('generalpolice-94737317-moex-00682', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '在室溫下有兩塊質量均為100公克的銅塊，各以100公尺/秒的速度相向運動，發生正面非彈性碰撞後，兩 塊銅塊合而為一且靜止不動。若在這個過程中，損失的動能完全轉換為熱能，則所產生的熱能約為多少卡？ （熱功當量為1卡 =4.2焦耳）', '["1,000卡", "500卡", "238卡", "119卡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00683', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '下列各溫標在不同條件下，有關溫度的敘述，何者正確？', '["月球背光面的溫度可能低於零下300℃", "72℃與72℉水之溫度相同", "水的固、液、氣三相點為273.16K", "人體溫度約為37℉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00684', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '在絕熱條件下，氣體的自由膨脹是一種不可逆的熱力學過程。有關氣體自由膨脹的各項物理性質，下列何 者錯誤？', '["內能不變", "系統的總熱量不變", "熵值不變", "氣體不對外作功"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00685', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一位引擎設計師，聲稱他製造出一台熱機，從100℃的高溫爐中吸收2,500J的熱能，並且在25℃的室溫 條件下排放出2,200J的熱能，下列敘述何者正確？', '["不可能，這個設計違反卡諾定理（Carnot''stheorem）", "不可能，這個設計違反熱力學第一定律", "不可能，這個設計違反熱力學第二定律", "這是一個完全符合熱力學定律的物理引擎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00686', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一片長方形玻璃窗，其長度為L、寬度為W、厚度為D。冬天室內室外溫度差固定為ΔT，為減少單位時間 內室內經由此片玻璃傳導到室外的熱量，則可採用下列何種方式？', '["L與D不變，增加W", "L與W不變，增加D", "L與W不變，減少D", "W與D不變，增加L"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00687', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '乾粉滅火器將瓶內乾粉向外噴射的工作原理，係利用壓下滅火器的把手後，當瓶內氣壓大於外界大氣壓力， 乾粉就會往外衝滅火，因此滅火器的本體容器也要有足夠的耐壓能力，才能將高壓氣體穩定封存於瓶內。 若不考慮容器漏氣及卸壓閥的作用，下列敘述何者正確？', '["滅火器本體容器之耐壓壓力值只要跟灌入的氣體蓄壓壓力相等即可", "根據理想氣體方程式可知，填入鋼瓶的氣體莫耳數多寡對造成的氣壓並無影響", "正常乾粉滅火器的壓力表讀值，在夏天高溫環境中會比在冬天低溫環境來得高", "理論上，當鋼瓶內的氣壓還有一大氣壓時，此滅火器還是可以噴出乾粉來滅火"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00688', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '1912年鐵達尼號啟航不久，即沉船於3,784公尺深的海底。若海面上的大氣壓力為1 atm＝1.01×105 Pa， 海水的密度為1.03g/cm3，重力加速度值為9.8m/s2，則鐵達尼號於海底沉船處的壓力，約為一大氣壓的幾 倍？', '["10", "100", "400", "1,200 1"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00689', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一實心小木塊置入一裝水的大燒杯中，有 的體積露出水面。若將燒杯中的水改為密度為1.5g/cm3的液體 8 時，則木塊露出液面的體積占其全部體積的比例為何？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
